    var FFX_CACHE_DIR  = "aeTools/Handoff";
    var FFX_CACHE_NAME = "Handoff.ffx";

    function ensureFFX() {
        var dir = new Folder(Folder.userData.fsName + "/" + FFX_CACHE_DIR);
        if (!dir.exists) { dir.create(); }
        var ffx = new File(dir.fsName + "/" + FFX_CACHE_NAME);

        // If the cached file is missing OR its size doesn't match the
        // embedded payload, rewrite it. (Catches the case where the user
        // updates the script to a new schema — the cache gets refreshed.)
        var needsWrite = !ffx.exists || ffx.length !== HANDOFF_FFX_BINARY.length;
        if (needsWrite) {
            if (HANDOFF_FFX_BINARY.length === 0) {
                throw new Error(
                    "Embedded Handoff.ffx is empty. Run `node tools/embed_ffx.js` "
                    + "from the aeTools repo root to populate it from "
                    + "handoff/Handoff.ffx, then reload this script."
                );
            }
            ffx.encoding = "BINARY";
            if (!ffx.open("w")) {
                throw new Error("Could not open " + ffx.fsName + " for writing.");
            }
            ffx.write(HANDOFF_FFX_BINARY);
            ffx.close();
        }
        return ffx;
    }

    // ---- Rig apply / remove --------------------------------------------------

    // Legacy flat-control name patterns, so removeRig can clean up rigs
    // built by older versions of Handoff.jsx that used 18-26 flat ADBE
    // Slider Controls at the top level of the layer.
    var LEGACY_PATTERNS = [
        /^Layer \d+$/,
        /^Weight \d+$/,
        /^Use Individual \d+$/,
        /^Pos Weight \d+$/,
        /^Rot Weight \d+$/,
        /^Scale Weight \d+$/
    ];
    var LEGACY_EXACT = [ "Use Individual Weights" ];

    // Match names of older Handoff pseudo effect versions, so removeRig
    // can clean up rigs left over from prior schemas. Append (don't
    // replace) when bumping HANDOFF_MATCHNAME — that's how we keep the
    // upgrade path painless for users with old rigs in their projects.
    var LEGACY_HANDOFF_MATCHNAMES = [
        "Pseudo/PEM Matchname"  // PEM default — used through commit 6a73f40
    ];

    function isLegacyEffect(name) {
        for (var i = 0; i < LEGACY_PATTERNS.length; i++) {
            if (LEGACY_PATTERNS[i].test(name)) { return true; }
        }
        for (var j = 0; j < LEGACY_EXACT.length; j++) {
            if (name === LEGACY_EXACT[j]) { return true; }
        }
        return false;
    }

    function isHandoffMatchname(mn) {
        if (mn === HANDOFF_MATCHNAME) { return true; }
        for (var i = 0; i < LEGACY_HANDOFF_MATCHNAMES.length; i++) {
            if (mn === LEGACY_HANDOFF_MATCHNAMES[i]) { return true; }
        }
        return false;
    }

    function findHandoffEffect(layer) {
        var fxPar = layer.property("ADBE Effect Parade");
        for (var i = 1; i <= fxPar.numProperties; i++) {
            var fx = fxPar.property(i);
            if (fx.name === EFFECT_NAME || isHandoffMatchname(fx.matchName)) {
                return fx;
            }
        }
        return null;
    }

    function removeRig(layer) {
        // Clear the three transform expressions first so they don\'t hold
        // references to controls we\'re about to delete.
        var tg = layer.property("ADBE Transform Group");
        var props = ["ADBE Position", "ADBE Rotate Z", "ADBE Scale"];
        for (var i = 0; i < props.length; i++) {
            var pr = tg.property(props[i]);
            if (pr.expressionEnabled) { pr.expression = ""; }
        }

        // Remove the Handoff pseudo effect (current and legacy matchnames)
        // AND any legacy flat controls left from very old script versions.
        // Iterate in reverse so removal by index doesn\'t shift what\'s left.
        var fxPar = layer.property("ADBE Effect Parade");
        for (var n = fxPar.numProperties; n >= 1; n--) {
            var fx = fxPar.property(n);
            if (fx.name === EFFECT_NAME || isHandoffMatchname(fx.matchName)) {
                fxPar.property(n).remove();
            } else if (isLegacyEffect(fx.name)) {
                fxPar.property(n).remove();
            }
        }
    }

    function selectOnly(layer) {
        var comp = layer.containingComp;
        for (var i = 1; i <= comp.numLayers; i++) {
            comp.layer(i).selected = false;
        }
        layer.selected = true;
    }

    function applyRig(layer, ffxFile) {
        // 1. Strip any prior rig (pseudo effect or legacy flat layout)
        removeRig(layer);

        // 2. applyPreset requires the target to be the sole selection —
        //    otherwise AE may create a new Solid layer for the preset
        //    instead of applying to our target.
        selectOnly(layer);

        // 3. Apply the pseudo effect. This auto-registers Pseudo/PEM Matchname
        //    in AE\'s runtime if not already registered.
        layer.applyPreset(ffxFile);
        if (findHandoffEffect(layer) === null) {
            throw new Error("applyPreset did not install the Handoff effect.");
        }

        // 4. Attach the three transform expressions. The position/rotation/
        //    scale expressions internally call wPropFor(p, channel) which
        //    reads each parent\'s "Use Individual Weights" checkbox and
        //    picks the active slider — shared P{n} Weight when off,
        //    per-channel P{n} Position/Rotation/Scale when on. Mutual
        //    exclusion is handled inside the expression math, so the
        //    sub-controls themselves carry no expressions and a user
        //    pressing EE on the layer sees just these three rows.
        var tg  = layer.property("ADBE Transform Group");
        tg.property("ADBE Position").expression  = EXPR_POSITION;
        tg.property("ADBE Rotate Z").expression  = EXPR_ROTATION;
        tg.property("ADBE Scale").expression     = EXPR_SCALE;
    }

